INSERT INTO public.spells (id, name, owner_id, source, visibility, level, school, casting_time, "range", components, duration, concentration, ritual, classes, description, higher_levels, save_type, attack_type, damage_dice, damage_type, damage_at_slot_level, damage_at_char_level, heal_dice, heal_at_slot_level, area_of_effect) VALUES
('guiding-bolt', 'Guiding Bolt', NULL, 'srd', 'private', 1, 'Evocation', '1 action', '120 feet', 'V, S', '1 round', false, false, '{"Cleric"}', 'A flash of light streaks toward a creature of your choice within range. Make a ranged spell attack against the target. On a hit, the target takes 4d6 radiant damage, and the next attack roll made against this target before the end of your next turn has advantage, thanks to the mystical dim light glittering on the target until then.', 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.', NULL, 'ranged', '4d6', 'Radiant', '{"1":"4d6","2":"5d6","3":"6d6","4":"7d6","5":"8d6","6":"9d6","7":"10d6","8":"11d6","9":"12d6"}'::jsonb, NULL, NULL, NULL, NULL),
('healing-word', 'Healing Word', NULL, 'srd', 'private', 1, 'Evocation', '1 bonus action', '60 feet', 'V', 'Instantaneous', false, false, '{"Bard","Cleric","Druid"}', 'A creature of your choice that you can see within range regains hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', 'When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d4 for each slot level above 1st.', NULL, NULL, NULL, NULL, NULL, NULL, '1d4 + MOD', '{"1":"1d4 + MOD","2":"2d4 + MOD","3":"3d4 + MOD","4":"4d4 + MOD","5":"5d4 + MOD","6":"6d4 + MOD","7":"7d4 + MOD","8":"8d4 + MOD","9":"9d4 + MOD"}'::jsonb, NULL),
('hellish-rebuke', 'Hellish Rebuke', NULL, 'srd', 'private', 1, 'Evocation', '1 reaction', '60 feet', 'V, S', 'Instantaneous', false, false, '{"Warlock"}', 'You point your finger, and the creature that damaged you is momentarily surrounded by hellish flames. The creature must make a dexterity saving throw. It takes 2d10 fire damage on a failed save, or half as much damage on a successful one.', 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d10 for each slot level above 1st.', 'DEX', NULL, '2d10', 'Fire', '{"1":"2d10","2":"3d10","3":"4d10","4":"5d10","5":"6d10","6":"7d10","7":"8d10","8":"9d10","9":"10d10"}'::jsonb, NULL, NULL, NULL, NULL),
('heroism', 'Heroism', NULL, 'srd', 'private', 1, 'Enchantment', '1 action', 'Touch', 'V, S', 'Up to 1 minute', true, false, '{"Bard","Paladin"}', 'A willing creature you touch is imbued with bravery. Until the spell ends, the creature is immune to being frightened and gains temporary hit points equal to your spellcasting ability modifier at the start of each of its turns. When the spell ends, the target loses any remaining temporary hit points from this spell.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('hideous-laughter', 'Hideous Laughter', NULL, 'srd', 'private', 1, 'Enchantment', '1 action', '30 feet', 'V, S, M (Tiny tarts and a feather that is waved in the air.)', 'Up to 1 minute', true, false, '{"Bard","Wizard"}', E'A creature of your choice that you can see within range perceives everything as hilariously funny and falls into fits of laughter if this spell affects it. The target must succeed on a wisdom saving throw or fall prone, becoming incapacitated and unable to stand up for the duration. A creature with an Intelligence score of 4 or less isn''t affected.\n\nAt the end of each of its turns, and each time it takes damage, the target can make another wisdom saving throw. The target had advantage on the saving throw if it''s triggered by damage. On a success, the spell ends.', NULL, 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('hunters-mark', 'Hunter''s Mark', NULL, 'srd', 'private', 1, 'Divination', '1 bonus action', '90 feet', 'V', 'Up to 1 hour', true, false, '{"Ranger"}', 'You choose a creature you can see within range and mystically mark it as your quarry. Until the spell ends, you deal an extra 1d6 damage to the target whenever you hit it with a weapon attack, and you have advantage on any Wisdom (Perception) or Wisdom (Survival) check you make to find it. If the target drops to 0 hit points before this spell ends, you can use a bonus action on a subsequent turn of yours to mark a new creature.', 'When you cast this spell using a spell slot of 3rd or 4th level, you can maintain your concentration on the spell for up to 8 hours. When you use a spell slot of 5th level or higher, you can maintain your concentration on the spell for up to 24 hours.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('identify', 'Identify', NULL, 'srd', 'private', 1, 'Divination', '1 minute', 'Touch', 'V, S, M (A pearl worth at least 100gp and an owl feather.)', 'Instantaneous', false, true, '{"Bard","Wizard","Psion"}', E'You choose one object that you must touch throughout the casting of the spell. If it is a magic item or some other magic-imbued object, you learn its properties and how to use them, whether it requires attunement to use, and how many charges it has, if any. You learn whether any spells are affecting the item and what they are. If the item was created by a spell, you learn which spell created it.\n\nIf you instead touch a creature throughout the casting, you learn what spells, if any, are currently affecting it.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('illusory-script', 'Illusory Script', NULL, 'srd', 'private', 1, 'Illusion', '1 minute', 'Touch', 'S, M (A lead-based ink worth at least 10gp, which this spell consumes.)', '10 days', false, true, '{"Bard","Warlock","Wizard"}', E'You write on parchment, paper, or some other suitable writing material and imbue it with a potent illusion that lasts for the duration.\n\nTo you and any creatures you designate when you cast the spell, the writing appears normal, written in your hand, and conveys whatever meaning you intended when you wrote the text. To all others, the writing appears as if it were written in an unknown or magical script that is unintelligible. Alternatively, you can cause the writing to appear to be an entirely different message, written in a different hand and language, though the language must be one you know.\n\nShould the spell be dispelled, the original script and the illusion both disappear.\n\nA creature with truesight can read the hidden message.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('inflict-wounds', 'Inflict Wounds', NULL, 'srd', 'private', 1, 'Necromancy', '1 action', 'Touch', 'V, S', 'Instantaneous', false, false, '{"Cleric"}', 'Make a melee spell attack against a creature you can reach. On a hit, the target takes 3d10 necrotic damage.', 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d10 for each slot level above 1st.', NULL, 'melee', '3d10', 'Necrotic', '{"1":"3d10","2":"4d10","3":"5d10","4":"6d10","5":"7d10","6":"8d10","7":"9d10","8":"10d10","9":"11d10"}'::jsonb, NULL, NULL, NULL, NULL),
('jump', 'Jump', NULL, 'srd', 'private', 1, 'Transmutation', '1 action', 'Touch', 'V, S, M (A grasshopper''s hind leg.)', '1 minute', false, false, '{"Druid","Ranger","Sorcerer","Wizard","Psion"}', 'You touch a creature. The creature''s jump distance is tripled until the spell ends.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('longstrider', 'Longstrider', NULL, 'srd', 'private', 1, 'Transmutation', '1 action', 'Touch', 'V, S, M (A pinch of dirt.)', '1 hour', false, false, '{"Bard","Druid","Ranger","Wizard","Psion"}', 'You touch a creature. The target''s speed increases by 10 feet until the spell ends.', 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each spell slot above 1st.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('mage-armor', 'Mage Armor', NULL, 'srd', 'private', 1, 'Abjuration', '1 action', 'Touch', 'V, S, M (A piece of cured leather.)', '8 hours', false, false, '{"Sorcerer","Wizard","Psion"}', 'You touch a willing creature who isn''t wearing armor, and a protective magical force surrounds it until the spell ends. The target''s base AC becomes 13 + its Dexterity modifier. The spell ends if the target dons armor or if you dismiss the spell as an action.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('magic-missile', 'Magic Missile', NULL, 'srd', 'private', 1, 'Evocation', '1 action', '120 feet', 'V, S', 'Instantaneous', false, false, '{"Sorcerer","Wizard"}', 'You create three glowing darts of magical force. Each dart hits a creature of your choice that you can see within range. A dart deals 1d4 + 1 force damage to its target. The darts all strike simultaneously, and you can direct them to hit one creature or several.', 'When you cast this spell using a spell slot of 2nd level or higher, the spell creates one more dart for each slot level above 1st.', NULL, NULL, '1d4 + 1', 'Force', '{"1":"1d4 + 1","2":"1d4 + 1","3":"1d4 + 1","4":"1d4 + 1","5":"1d4 + 1","6":"1d4 + 1","7":"1d4 + 1","8":"1d4 + 1","9":"1d4 + 1"}'::jsonb, NULL, NULL, NULL, NULL),
('protection-from-evil-and-good', 'Protection from Evil and Good', NULL, 'srd', 'private', 1, 'Abjuration', '1 action', 'Touch', 'V, S, M (Holy water or powdered silver and iron, which the spell consumes.)', 'Up to 10 minutes', true, false, '{"Cleric","Paladin","Warlock","Wizard"}', E'Until the spell ends, one willing creature you touch is protected against certain types of creatures: aberrations, celestials, elementals, fey, fiends, and undead.\n\nThe protection grants several benefits. Creatures of those types have disadvantage on attack rolls against the target. The target also can''t be charmed, frightened, or possessed by them. If the target is already charmed, frightened, or possessed by such a creature, the target has advantage on any new saving throw against the relevant effect.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('purify-food-and-drink', 'Purify Food and Drink', NULL, 'srd', 'private', 1, 'Transmutation', '1 action', '10 feet', 'V, S', 'Instantaneous', false, true, '{"Cleric","Druid","Paladin"}', 'All nonmagical food and drink within a 5-foot radius sphere centered on a point of your choice within range is purified and rendered free of poison and disease.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('sanctuary', 'Sanctuary', NULL, 'srd', 'private', 1, 'Abjuration', '1 bonus action', '30 feet', 'V, S, M (A small silver mirror.)', '1 minute', false, false, '{"Cleric"}', E'You ward a creature within range against attack. Until the spell ends, any creature who targets the warded creature with an attack or a harmful spell must first make a wisdom saving throw. On a failed save, the creature must choose a new target or lose the attack or spell. This spell doesn''t protect the warded creature from area effects, such as the explosion of a fireball.\n\nIf the warded creature makes an attack or casts a spell that affects an enemy creature, this spell ends.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('shield', 'Shield', NULL, 'srd', 'private', 1, 'Abjuration', '1 reaction', 'Self', 'V, S', '1 round', false, false, '{"Sorcerer","Wizard","Psion"}', 'An invisible barrier of magical force appears and protects you. Until the start of your next turn, you have a +5 bonus to AC, including against the triggering attack, and you take no damage from magic missile.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('shield-of-faith', 'Shield of Faith', NULL, 'srd', 'private', 1, 'Abjuration', '1 bonus action', '60 feet', 'V, S, M (A small parchment with a bit of holy text written on it.)', 'Up to 10 minutes', true, false, '{"Cleric","Paladin"}', 'A shimmering field appears and surrounds a creature of your choice within range, granting it a +2 bonus to AC for the duration.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('silent-image', 'Silent Image', NULL, 'srd', 'private', 1, 'Illusion', '1 action', '60 feet', 'V, S, M (A bit of fleece.)', 'Up to 10 minutes', true, false, '{"Bard","Sorcerer","Wizard","Psion"}', E'You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 15-foot cube. The image appears at a spot within range and lasts for the duration. The image is purely visual; it isn''t accompanied by sound, smell, or other sensory effects.\n\nYou can use your action to cause the image to move to any spot within range. As the image changes location, you can alter its appearance so that its movements appear natural for the image. For example, if you create an image of a creature and move it, you can alter the image so that it appears to be walking.\n\nPhysical interaction with the image reveals it to be an illusion, because things can pass through it. A creature that uses its action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"cube","size":15}'::jsonb),
('sleep', 'Sleep', NULL, 'srd', 'private', 1, 'Enchantment', '1 action', '90 feet', 'V, S, M (A pinch of fine sand, rose petals, or a cricket.)', '1 minute', false, false, '{"Bard","Sorcerer","Wizard","Psion"}', E'This spell sends creatures into a magical slumber. Roll 5d8; the total is how many hit points of creatures this spell can affect. Creatures within 20 feet of a point you choose within range are affected in ascending order of their current hit points (ignoring unconscious creatures).\n\nStarting with the creature that has the lowest current hit points, each creature affected by this spell falls unconscious until the spell ends, the sleeper takes damage, or someone uses an action to shake or slap the sleeper awake. Subtract each creature''s hit points from the total before moving on to the creature with the next lowest hit points. A creature''s hit points must be equal to or less than the remaining total for that creature to be affected.\n\nUndead and creatures immune to being charmed aren''t affected by this spell.', 'When you cast this spell using a spell slot of 2nd level or higher, roll an additional 2d8 for each slot level above 1st.', NULL, NULL, '5d8', NULL, '{"1":"5d8"}'::jsonb, NULL, NULL, NULL, '{"type":"sphere","size":20}'::jsonb),
('speak-with-animals', 'Speak with Animals', NULL, 'srd', 'private', 1, 'Divination', '1 action', 'Self', 'V, S', '10 minutes', false, true, '{"Bard","Druid","Ranger","Psion"}', 'You gain the ability to comprehend and verbally communicate with beasts for the duration. The knowledge and awareness of many beasts is limited by their intelligence, but at a minimum, beasts can give you information about nearby locations and monsters, including whatever they can perceive or have perceived within the past day. You might be able to persuade a beast to perform a small favor for you, at the GM''s discretion.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('thunderwave', 'Thunderwave', NULL, 'srd', 'private', 1, 'Evocation', '1 action', 'Self', 'V, S', 'Instantaneous', false, false, '{"Bard","Druid","Sorcerer","Wizard","Psion"}', E'A wave of thunderous force sweeps out from you. Each creature in a 15-foot cube originating from you must make a constitution saving throw. On a failed save, a creature takes 2d8 thunder damage and is pushed 10 feet away from you. On a successful save, the creature takes half as much damage and isn''t pushed.\n\nIn addition, unsecured objects that are completely within the area of effect are automatically pushed 10 feet away from you by the spell''s effect, and the spell emits a thunderous boom audible out to 300 feet.', 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d8 for each slot level above 1st.', 'CON', NULL, '2d8', 'Thunder', '{"1":"2d8","2":"3d8","3":"4d8","4":"5d8","5":"6d8","6":"7d8","7":"8d8","8":"9d8","9":"10d8"}'::jsonb, NULL, NULL, NULL, '{"type":"cube","size":15}'::jsonb),
('unseen-servant', 'Unseen Servant', NULL, 'srd', 'private', 1, 'Conjuration', '1 action', '60 feet', 'V, S, M (A piece of string and a bit of wood.)', '1 hour', false, true, '{"Bard","Warlock","Wizard"}', E'This spell creates an invisible, mindless, shapeless force that performs simple tasks at your command until the spell ends. The servant springs into existence in an unoccupied space on the ground within range. It has AC 10, 1 hit point, and a Strength of 2, and it can''t attack. If it drops to 0 hit points, the spell ends.\n\nOnce on each of your turns as a bonus action, you can mentally command the servant to move up to 15 feet and interact with an object. The servant can perform simple tasks that a human servant could do, such as fetching things, cleaning, mending, folding clothes, lighting fires, serving food, and pouring wine. Once you give the command, the servant performs the task to the best of its ability until it completes the task, then waits for your next command.\n\nIf you command the servant to perform a task that would move it more than 60 feet away from you, the spell ends.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('acid-arrow', 'Acid Arrow', NULL, 'srd', 'private', 2, 'Evocation', '1 action', '90 feet', 'V, S, M (Powdered rhubarb leaf and an adder''s stomach.)', 'Instantaneous', false, false, '{"Wizard"}', 'A shimmering green arrow streaks toward a target within range and bursts in a spray of acid. Make a ranged spell attack against the target. On a hit, the target takes 4d4 acid damage immediately and 2d4 acid damage at the end of its next turn. On a miss, the arrow splashes the target with acid for half as much of the initial damage and no damage at the end of its next turn.', 'When you cast this spell using a spell slot of 3rd level or higher, the damage (both initial and later) increases by 1d4 for each slot level above 2nd.', NULL, 'ranged', '4d4', 'Acid', '{"2":"4d4","3":"5d4","4":"6d4","5":"7d4","6":"8d4","7":"9d4","8":"10d4","9":"11d4"}'::jsonb, NULL, NULL, NULL, NULL),
('aid', 'Aid', NULL, 'srd', 'private', 2, 'Abjuration', '1 action', '30 feet', 'V, S, M (A tiny strip of white cloth.)', '8 hours', false, false, '{"Cleric","Paladin"}', 'Your spell bolsters your allies with toughness and resolve. Choose up to three creatures within range. Each target''s hit point maximum and current hit points increase by 5 for the duration.', 'When you cast this spell using a spell slot of 3rd level or higher, a target''s hit points increase by an additional 5 for each slot level above 2nd.', NULL, NULL, NULL, NULL, NULL, NULL, '5', '{"2":"5","3":"10","4":"15","5":"20","6":"25","7":"30","8":"35","9":"40"}'::jsonb, NULL),
('alter-self', 'Alter Self', NULL, 'srd', 'private', 2, 'Transmutation', '1 action', 'Self', 'V, S', 'Up to 1 hour', true, false, '{"Sorcerer","Wizard"}', E'You assume a different form. When you cast the spell, choose one of the following options, the effects of which last for the duration of the spell. While the spell lasts, you can end one option as an action to gain the benefits of a different one.\n\n***Aquatic Adaptation.*** You adapt your body to an aquatic environment, sprouting gills and growing webbing between your fingers. You can breathe underwater and gain a swimming speed equal to your walking speed.\n\n***Change Appearance.*** You transform your appearance. You decide what you look like, including your height, weight, facial features, sound of your voice, hair length, coloration, and distinguishing characteristics, if any. You can make yourself appear as a member of another race, though none of your statistics change. You also can''t appear as a creature of a different size than you, and your basic shape stays the same; if you''re bipedal, you can''t use this spell to become quadrupedal, for instance. At any time for the duration of the spell, you can use your action to change your appearance in this way again.\n\n***Natural Weapons.*** You grow claws, fangs, spines, horns, or a different natural weapon of your choice. Your unarmed strikes deal 1d6 bludgeoning, piercing, or slashing damage, as appropriate to the natural weapon you chose, and you are proficient with your unarmed strikes. Finally, the natural weapon is magic and you have a +1 bonus to the attack and damage rolls you make using it.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('animal-messenger', 'Animal Messenger', NULL, 'srd', 'private', 2, 'Enchantment', '1 action', '30 feet', 'V, S, M (A morsel of food.)', '24 hours', false, true, '{"Bard","Druid","Ranger","Psion"}', E'By means of this spell, you use an animal to deliver a message. Choose a Tiny beast you can see within range, such as a squirrel, a blue jay, or a bat. You specify a location, which you must have visited, and a recipient who matches a general description, such as "a man or woman dressed in the uniform of the town guard" or "a red-haired dwarf wearing a pointed hat." You also speak a message of up to twenty-five words. The target beast travels for the duration of the spell toward the specified location, covering about 50 miles per 24 hours for a flying messenger, or 25 miles for other animals.\n\nWhen the messenger arrives, it delivers your message to the creature that you described, replicating the sound of your voice. The messenger speaks only to a creature matching the description you gave. If the messenger doesn''t reach its destination before the spell ends, the message is lost, and the beast makes its way back to where you cast this spell.', 'If you cast this spell using a spell slot of 3nd level or higher, the duration of the spell increases by 48 hours for each slot level above 2nd.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('arcane-lock', 'Arcane Lock', NULL, 'srd', 'private', 2, 'Abjuration', '1 action', 'Touch', 'V, S, M (Gold dust worth at least 25gp, which the spell consumes.)', 'Until dispelled', false, false, '{"Wizard"}', E'You touch a closed door, window, gate, chest, or other entryway, and it becomes locked for the duration. You and the creatures you designate when you cast this spell can open the object normally. You can also set a password that, when spoken within 5 feet of the object, suppresses this spell for 1 minute. Otherwise, it is impassable until it is broken or the spell is dispelled or suppressed. Casting knock on the object suppresses arcane lock for 10 minutes.\n\nWhile affected by this spell, the object is more difficult to break or force open; the DC to break it or pick any locks on it increases by 10.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('arcanists-magic-aura', 'Arcanist''s Magic Aura', NULL, 'srd', 'private', 2, 'Illusion', '1 action', 'Touch', 'V, S, M (A small square of silk.)', '24 hours', false, false, '{"Wizard"}', E'You place an illusion on a creature or an object you touch so that divination spells reveal false information about it. The target can be a willing creature or an object that isn''t being carried or worn by another creature.\n\nWhen you cast the spell, choose one or both of the following effects. The effect lasts for the duration. If you cast this spell on the same creature or object every day for 30 days, placing the same effect on it each time, the illusion lasts until it is dispelled.\n\n***False Aura.*** You change the way the target appears to spells and magical effects, such as detect magic, that detect magical auras. You can make a nonmagical object appear magical, a magical object appear nonmagical, or change the object''s magical aura so that it appears to belong to a specific school of magic that you choose. When you use this effect on an object, you can make the false magic apparent to any creature that handles the item.\n\n***Mask.*** You change the way the target appears to spells and magical effects that detect creature types, such as a paladin''s Divine Sense or the trigger of a symbol spell. You choose a creature type and other spells and magical effects treat the target as if it were a creature of that type or of that alignment.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('augury', 'Augury', NULL, 'srd', 'private', 2, 'Divination', '1 minute', 'Self', 'V, S, M (Specially marked sticks, bones, or similar tokens worth at least 25gp.)', 'Instantaneous', false, true, '{"Cleric"}', E'By casting gem-inlaid sticks, rolling dragon bones, laying out ornate cards, or employing some other divining tool, you receive an omen from an otherworldly entity about the results of a specific course of action that you plan to take within the next 30 minutes. The GM chooses from the following possible omens:\n\n- Weal, for good results\n\n- Woe, for bad results\n\n- Weal and woe, for both good and bad results\n\n- Nothing, for results that aren''t especially good or bad\n\nThe spell doesn''t take into account any possible circumstances that might change the outcome, such as the casting of additional spells or the loss or gain of a companion.\n\nIf you cast the spell two or more times before completing your next long rest, there is a cumulative 25 percent chance for each casting after the first that you get a random reading. The GM makes this roll in secret.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('aura-of-vitality', 'Aura of Vitality', NULL, 'srd', 'private', 3, 'Evocation', '1 action', 'Self (30-foot radius)', 'V', 'Up to 1 minute', true, false, '{"Cleric","Druid","Paladin","Psion"}', 'Healing energy radiates from you in an aura with a 30-foot radius. Until the spell ends, the aura moves with you, centered on you. You can use a bonus action to cause one creature in the aura (including you) to regain 2d6 hit points.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2d6', NULL, NULL),
('barkskin', 'Barkskin', NULL, 'srd', 'private', 2, 'Transmutation', '1 action', 'Touch', 'V, S, M (A handful of oak bark.)', 'Up to 1 hour', true, false, '{"Druid","Ranger"}', 'You touch a willing creature. Until the spell ends, the target''s skin has a rough, bark-like appearance, and the target''s AC can''t be less than 16, regardless of what kind of armor it is wearing.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('blindness-deafness', 'Blindness/Deafness', NULL, 'srd', 'private', 2, 'Necromancy', '1 action', '30 feet', 'V', '1 minute', false, false, '{"Bard","Cleric","Sorcerer","Wizard","Psion"}', 'You can blind or deafen a foe. Choose one creature that you can see within range to make a constitution saving throw. If it fails, the target is either blinded or deafened (your choice) for the duration. At the end of each of its turns, the target can make a constitution saving throw. On a success, the spell ends.', 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd.', 'CON', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('blur', 'Blur', NULL, 'srd', 'private', 2, 'Illusion', '1 action', 'Self', 'V', 'Up to 1 minute', true, false, '{"Sorcerer","Wizard"}', 'Your body becomes blurred, shifting and wavering to all who can see you. For the duration, any creature has disadvantage on attack rolls against you. An attacker is immune to this effect if it doesn''t rely on sight, as with blindsight, or can see through illusions, as with truesight.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('branding-smite', 'Branding Smite', NULL, 'srd', 'private', 2, 'Evocation', '1 bonus action', 'Self', 'V', 'Up to 1 minute', true, false, '{"Paladin"}', 'The next time you hit a creature with a weapon attack before this spell ends, the weapon gleams with astral radiance as you strike. The attack deals an extra 2d6 radiant damage to the target, which becomes visible if it''s invisible, and the target sheds dim light in a 5-foot radius and can''t become invisible until the spell ends.', 'When you cast this spell using a spell slot of 3rd level or higher, the extra damage increases by 1d6 for each slot level above 2nd.', NULL, NULL, '2d6', 'Radiant', '{"2":"2d6","3":"3d6","4":"4d6","5":"5d6","6":"6d6","7":"7d6","8":"8d6","9":"9d6"}'::jsonb, NULL, NULL, NULL, NULL),
('calm-emotions', 'Calm Emotions', NULL, 'srd', 'private', 2, 'Enchantment', '1 action', '60 feet', 'V, S', 'Up to 1 minute', true, false, '{"Bard","Cleric","Psion"}', E'You attempt to suppress strong emotions in a group of people. Each humanoid in a 20-foot-radius sphere centered on a point you choose within range must make a charisma saving throw; a creature can choose to fail this saving throw if it wishes. If a creature fails its saving throw, choose one of the following two effects. You can suppress any effect causing a target to be charmed or frightened. When this spell ends, any suppressed effect resumes, provided that its duration has not expired in the meantime.\n\nAlternatively, you can make a target indifferent about creatures of your choice that it is hostile toward. This indifference ends if the target is attacked or harmed by a spell or if it witnesses any of its friends being harmed. When the spell ends, the creature becomes hostile again, unless the GM rules otherwise.', NULL, 'CHA', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"sphere","size":20}'::jsonb),
('continual-flame', 'Continual Flame', NULL, 'srd', 'private', 2, 'Evocation', '1 action', 'Touch', 'V, S, M (Ruby dust worth 50 gp, which the spell consumes.)', 'Until dispelled', false, false, '{"Cleric","Wizard"}', 'A flame, equivalent in brightness to a torch, springs forth from an object that you touch. The effect looks like a regular flame, but it creates no heat and doesn''t use oxygen. A continual flame can be covered or hidden but not smothered or quenched.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('darkness', 'Darkness', NULL, 'srd', 'private', 2, 'Evocation', '1 action', '60 feet', 'V, M (Bat fur and a drop of pitch or piece of coal.)', 'Up to 10 minutes', true, false, '{"Sorcerer","Warlock","Wizard"}', E'Magical darkness spreads from a point you choose within range to fill a 15-foot-radius sphere for the duration. The darkness spreads around corners. A creature with darkvision can''t see through this darkness, and nonmagical light can''t illuminate it.\n\nIf the point you choose is on an object you are holding or one that isn''t being worn or carried, the darkness emanates from the object and moves with it. Completely covering the source of the darkness with an opaque object, such as a bowl or a helm, blocks the darkness.\n\nIf any of this spell''s area overlaps with an area of light created by a spell of 2nd level or lower, the spell that created the light is dispelled.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"sphere","size":15}'::jsonb),
('darkvision', 'Darkvision', NULL, 'srd', 'private', 2, 'Transmutation', '1 action', 'Touch', 'V, S, M (Either a pinch of dried carrot or an agate.)', '8 hours', false, false, '{"Druid","Ranger","Sorcerer","Wizard"}', 'You touch a willing creature to grant it the ability to see in the dark. For the duration, that creature has darkvision out to a range of 60 feet.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('detect-thoughts', 'Detect Thoughts', NULL, 'srd', 'private', 2, 'Divination', '1 action', 'Self', 'V, S, M (A copper coin.)', 'Up to 1 minute', true, false, '{"Bard","Sorcerer","Wizard","Psion"}', E'For the duration, you can read the thoughts of certain creatures. When you cast the spell and as your action on each turn until the spell ends, you can focus your mind on any one creature that you can see within 30 feet of you. If the creature you choose has an Intelligence of 3 or lower or doesn''t speak any language, the creature is unaffected.\n\nYou initially learn the surface thoughts of the creature - what is most on its mind in that moment. As an action, you can either shift your attention to another creature''s thoughts or attempt to probe deeper into the same creature''s mind. If you probe deeper, the target must make a Wisdom saving throw. If it fails, you gain insight into its reasoning (if any), its emotional state, and something that looms large in its mind (such as something it worries over, loves, or hates). If it succeeds, the spell ends. Either way, the target knows that you are probing into its mind, and unless you shift your attention to another creature''s thoughts, the creature can use its action on its turn to make an Intelligence check contested by your Intelligence check; if it succeeds, the spell ends.\n\nQuestions verbally directed at the target creature naturally shape the course of its thoughts, so this spell is particularly effective as part of an interrogation.\n\nYou can also use this spell to detect the presence of thinking creatures you can''t see. When you cast the spell or as your action during the duration, you can search for thoughts within 30 feet of you. The spell can penetrate barriers, but 2 feet of rock, 2 inches of any metal other than lead, or a thin sheet of lead blocks you. You can''t detect a creature with an Intelligence of 3 or lower or one that doesn''t speak any language.\n\nOnce you detect the presence of a creature in this way, you can read its thoughts for the rest of the duration as described above, even if you can''t see it, but it must still be within range.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('enhance-ability', 'Enhance Ability', NULL, 'srd', 'private', 2, 'Transmutation', '1 action', 'Touch', 'V, S, M (Fur or a feather from a beast.)', 'Up to 1 hour', true, false, '{"Bard","Cleric","Druid","Sorcerer","Psion"}', E'You touch a creature and bestow upon it a magical enhancement. Choose one of the following effects; the target gains that effect until the spell ends.\n\n***Bear''s Endurance.*** The target has advantage on constitution checks. It also gains 2d6 temporary hit points, which are lost when the spell ends.\n\n***Bull''s Strength.*** The target has advantage on strength checks, and his or her carrying capacity doubles.\n\n***Cat''s Grace.*** The target has advantage on dexterity checks. It also doesn''t take damage from falling 20 feet or less if it isn''t incapacitated.\n\n***Eagle''s Splendor.*** The target has advantage on Charisma checks.\n\n***Fox''s Cunning.*** The target has advantage on intelligence checks.\n\n***Owl''s Wisdom.*** The target has advantage on wisdom checks.', 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('enlarge-reduce', 'Enlarge/Reduce', NULL, 'srd', 'private', 2, 'Transmutation', '1 action', '30 feet', 'V, S, M (A pinch iron powder.)', 'Up to 1 minute', true, false, '{"Sorcerer","Wizard","Psion"}', E'You cause a creature or an object you can see within range to grow larger or smaller for the duration. Choose either a creature or an object that is neither worn nor carried. If the target is unwilling, it can make a Constitution saving throw. On a success, the spell has no effect.\n\nIf the target is a creature, everything it is wearing and carrying changes size with it. Any item dropped by an affected creature returns to normal size at once.\n\n***Enlarge.*** The target''s size doubles in all dimensions, and its weight is multiplied by eight. This growth increases its size by one category-from Medium to Large, for example. If there isn''t enough room for the target to double its size, the creature or object attains the maximum possible size in the space available. Until the spell ends, the target also has advantage on Strength checks and Strength saving throws. The target''s weapons also grow to match its new size. While these weapons are enlarged, the target''s attacks with them deal 1d4 extra damage.\n\n***Reduce.*** The target''s size is halved in all dimensions, and its weight is reduced to one-eighth of normal. This reduction decreases its size by one category-from Medium to Small, for example. Until the spell ends, the target also has disadvantage on Strength checks and Strength saving throws. The target''s weapons also shrink to match its new size. While these weapons are reduced, the target''s attacks with them deal 1d4 less damage (this can''t reduce the damage below 1).', NULL, 'CON', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('enthrall', 'Enthrall', NULL, 'srd', 'private', 2, 'Enchantment', '1 action', '60 feet', 'V, S', '1 minute', false, false, '{"Bard","Warlock","Psion"}', 'You weave a distracting string of words, causing creatures of your choice that you can see within range and that can hear you to make a wisdom saving throw. Any creature that can''t be charmed succeeds on this saving throw automatically, and if you or your companions are fighting a creature, it has advantage on the save. On a failed save, the target has disadvantage on Wisdom (Perception) checks made to perceive any creature other than you until the spell ends or until the target can no longer hear you. The spell ends if you are incapacitated or can no longer speak.', NULL, 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('find-steed', 'Find Steed', NULL, 'srd', 'private', 2, 'Conjuration', '10 minutes', '30 feet', 'V, S', 'Instantaneous', false, false, '{"Paladin"}', E'You summon a spirit that assumes the form of an unusually intelligent, strong, and loyal steed, creating a long-lasting bond with it. Appearing in an unoccupied space within range, the steed takes on a form that you choose, such as a warhorse, a pony, a camel, an elk, or a mastiff. (Your GM might allow other animals to be summoned as steeds.) The steed has the statistics of the chosen form, though it is a celestial, fey, or fiend (your choice) instead of its normal type. Additionally, if your steed has an Intelligence of 5 or less, its Intelligence becomes 6, and it gains the ability to understand one language of your choice that you speak.\n\nYour steed serves you as a mount, both in combat and out, and you have an instinctive bond with it that allows you to fight as a seamless unit. While mounted on your steed, you can make any spell you cast that targets only you also target your steed.\n\nWhen the steed drops to 0 hit points, it disappears, leaving behind no physical form. You can also dismiss your steed at any time as an action, causing it to disappear. In either case, casting this spell again summons the same steed, restored to its hit point maximum.\n\nWhile your steed is within 1 mile of you, you can communicate with it telepathically.\n\nYou can''t have more than one steed bonded by this spell at a time. As an action, you can release the steed from its bond at any time, causing it to disappear.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('find-traps', 'Find Traps', NULL, 'srd', 'private', 2, 'Divination', '1 action', '120 feet', 'V, S', 'Instantaneous', false, false, '{"Cleric","Druid","Ranger"}', E'You sense the presence of any trap within range that is within line of sight. A trap, for the purpose of this spell, includes anything that would inflict a sudden or unexpected effect you consider harmful or undesirable, which was specifically intended as such by its creator. Thus, the spell would sense an area affected by the alarm spell, a glyph of warding, or a mechanical pit trap, but it would not reveal a natural weakness in the floor, an unstable ceiling, or a hidden sinkhole.\n\nThis spell merely reveals that a trap is present. You don''t learn the location of each trap, but you do learn the general nature of the danger posed by a trap you sense.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('flame-blade', 'Flame Blade', NULL, 'srd', 'private', 2, 'Evocation', '1 bonus action', 'Self', 'V, S, M (Leaf of sumac.)', 'Up to 10 minutes', true, false, '{"Druid"}', E'You evoke a fiery blade in your free hand. The blade is similar in size and shape to a scimitar, and it lasts for the duration. If you let go of the blade, it disappears, but you can evoke the blade again as a bonus action.\n\nYou can use your action to make a melee spell attack with the fiery blade. On a hit, the target takes 3d6 fire damage.\n\nThe flaming blade sheds bright light in a 10-foot radius and dim light for an additional 10 feet.', 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for every two slot levels above 2nd.', NULL, NULL, '3d6', 'Fire', '{"2":"3d6","4":"4d6","6":"5d6","8":"6d6"}'::jsonb, NULL, NULL, NULL, NULL),
('flaming-sphere', 'Flaming Sphere', NULL, 'srd', 'private', 2, 'Conjuration', '1 action', '60 feet', 'V, S, M (A bit of tallow, a pinch of brimstone, and a dusting of powdered iron.)', 'Up to 1 minute', true, false, '{"Druid","Wizard"}', E'A 5-foot-diameter sphere of fire appears in an unoccupied space of your choice within range and lasts for the duration. Any creature that ends its turn within 5 feet of the sphere must make a dexterity saving throw. The creature takes 2d6 fire damage on a failed save, or half as much damage on a successful one.\n\nAs a bonus action, you can move the sphere up to 30 feet. If you ram the sphere into a creature, that creature must make the saving throw against the sphere''s damage, and the sphere stops moving this turn.\n\nWhen you move the sphere, you can direct it over barriers up to 5 feet tall and jump it across pits up to 10 feet wide. The sphere ignites flammable objects not being worn or carried, and it sheds bright light in a 20-foot radius and dim light for an additional 20 feet.', 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d6 for each slot level above 2nd.', NULL, NULL, '2d6', 'Fire', '{"2":"2d6","3":"3d6","4":"4d6","5":"5d6","6":"6d6","7":"7d6","8":"8d6","9":"9d6"}'::jsonb, NULL, NULL, NULL, NULL),
('gentle-repose', 'Gentle Repose', NULL, 'srd', 'private', 2, 'Necromancy', '1 action', 'Touch', 'V, S, M (A pinch of salt and one copper piece placed on each of the corpse''s eyes, which must remain there for the duration.)', '10 days', false, true, '{"Cleric","Wizard"}', E'You touch a corpse or other remains. For the duration, the target is protected from decay and can''t become undead.\n\nThe spell also effectively extends the time limit on raising the target from the dead, since days spent under the influence of this spell don''t count against the time limit of spells such as raise dead.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('gust-of-wind', 'Gust of Wind', NULL, 'srd', 'private', 2, 'Evocation', '1 action', 'Self', 'V, S, M (A legume seed.)', 'Up to 1 minute', true, false, '{"Druid","Sorcerer","Wizard"}', E'A line of strong wind 60 feet long and 10 feet wide blasts from you in a direction you choose for the spell''s duration. Each creature that starts its turn in the line must succeed on a strength saving throw or be pushed 15 feet away from you in a direction following the line.\n\nAny creature in the line must spend 2 feet of movement for every 1 foot it moves when moving closer to you.\n\nThe gust disperses gas or vapor, and it extinguishes candles, torches, and similar unprotected flames in the area. It causes protected flames, such as those of lanterns, to dance wildly and has a 50 percent chance to extinguish them.\n\nAs a bonus action on each of your turns before the spell ends, you can change the direction in which the line blasts from you.', NULL, 'STR', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"line","size":60}'::jsonb),
('heat-metal', 'Heat Metal', NULL, 'srd', 'private', 2, 'Transmutation', '1 action', '60 feet', 'V, S, M (A piece of iron and a flame.)', 'Up to 1 minute', true, false, '{"Bard","Druid","Psion"}', E'Choose a manufactured metal object, such as a metal weapon or a suit of heavy or medium metal armor, that you can see within range. You cause the object to glow red-hot. Any creature in physical contact with the object takes 2d8 fire damage when you cast the spell. Until the spell ends, you can use a bonus action on each of your subsequent turns to cause this damage again.\n\nIf a creature is holding or wearing the object and takes the damage from it, the creature must succeed on a constitution saving throw or drop the object if it can. If it doesn''t drop the object, it has disadvantage on attack rolls and ability checks until the start of your next turn.', 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d8 for each slot level above 2nd.', 'CON', NULL, '2d8', 'Fire', '{"2":"2d8","3":"3d8","4":"4d8","5":"5d8","6":"6d8","7":"7d8","8":"8d8","9":"9d8"}'::jsonb, NULL, NULL, NULL, NULL)
